import type { CellGrid, CursorPosition, SelectionRange } from './types.js';

export interface NormalizedSelectionRange {
  start: CursorPosition;
  end: CursorPosition;
}

export interface SelectionTextOptions {
  /** Separator between selected terminal rows. Default `\n`. */
  lineSeparator?: string;
  /** Trim trailing spaces from each selected row. Default `true`. */
  trimRight?: boolean;
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, Math.floor(value)));
}

function comparePosition(left: CursorPosition, right: CursorPosition): number {
  if (left.row !== right.row) return left.row - right.row;
  return left.col - right.col;
}

/**
 * Normalize a terminal selection range into document order and clamp it to the
 * grid. `end.col` is exclusive, matching the live Rift selection overlay.
 */
export function normalizeSelectionRange(range: SelectionRange, grid: Pick<CellGrid, 'width' | 'height'>): NormalizedSelectionRange | null {
  if (grid.width <= 0 || grid.height <= 0) return null;
  if (!Number.isFinite(range.start.row) || !Number.isFinite(range.start.col) || !Number.isFinite(range.end.row) || !Number.isFinite(range.end.col)) {
    return null;
  }

  const first = comparePosition(range.start, range.end) <= 0 ? range.start : range.end;
  const second = first === range.start ? range.end : range.start;
  const start = {
    row: clamp(first.row, 0, grid.height - 1),
    col: clamp(first.col, 0, grid.width),
  };
  const end = {
    row: clamp(second.row, 0, grid.height - 1),
    col: clamp(second.col, 0, grid.width),
  };

  if (start.row === end.row && end.col <= start.col) return null;
  return { start, end };
}

/**
 * Extract plain text from a CellGrid selection. Empty placeholder cells are
 * skipped so wide-glyph continuation cells do not duplicate text.
 */
export function extractSelectionText(grid: CellGrid, range: SelectionRange, options: SelectionTextOptions = {}): string {
  const normalized = normalizeSelectionRange(range, grid);
  if (!normalized) return '';

  const lineSeparator = options.lineSeparator ?? '\n';
  const trimRight = options.trimRight !== false;
  const lines: string[] = [];

  for (let row = normalized.start.row; row <= normalized.end.row; row += 1) {
    const cells = grid.cells[row] ?? [];
    const startCol = row === normalized.start.row ? normalized.start.col : 0;
    const endCol = row === normalized.end.row ? normalized.end.col : grid.width;
    let line = '';
    for (let col = startCol; col < endCol; col += 1) {
      line += cells[col]?.char ?? ' ';
    }
    lines.push(trimRight ? line.trimEnd() : line);
  }

  return lines.join(lineSeparator);
}
