/**
 * Default CSS styles for the Rift terminal.
 *
 * Injected once into the document <head> via `injectRiftStyles()`.
 * Also exported as a raw string for custom injection (e.g. Shadow DOM).
 */

/** The complete CSS stylesheet for Rift terminals */
export const RIFT_CSS = `
.rift-terminal {
  background: #000;
  color: #c8d6e5;
  font-variant-ligatures: none;
  font-feature-settings: 'liga' 0, 'calt' 0;
  font-kerning: none;
  white-space: pre;
  overflow: hidden;
  tab-size: 8;
  letter-spacing: 0;
  text-rendering: optimizeSpeed;
  box-sizing: border-box;
  padding: 0;
  margin: 0;
  cursor: inherit;
}
.rift-row {
  display: block;
  height: var(--rift-row-height, 1em);
  line-height: var(--rift-row-height, 1em);
  white-space: pre;
}
.rift-row span,
.rift-row a {
  display: inline-block;
  height: var(--rift-row-height, 1em);
  line-height: inherit;
  white-space: pre;
  overflow: hidden;
  margin: 0;
  padding: 0;
  border: 0;
  box-sizing: border-box;
  vertical-align: top;
  transition:
    color 140ms linear,
    background-color 140ms linear,
    opacity 140ms linear,
    text-decoration-color 140ms linear;
}
.rift-terminal a {
  color: inherit;
  text-decoration: underline;
  cursor: pointer;
}
.rift-terminal a:hover {
  opacity: 0.8;
}
.rift-cursor-blink {
  animation: rift-blink 1s step-start infinite;
}
@keyframes rift-blink {
  50% { opacity: 0; }
}
`.trim();

const STYLE_ID = 'rift-default-styles';

/**
 * Inject the default Rift stylesheet into the document <head>.
 *
 * Safe to call multiple times — the <style> tag is only inserted once.
 * No-ops in non-browser environments (no `document`).
 */
export function injectRiftStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;

  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = RIFT_CSS;
  document.head.appendChild(style);
}
