/**
 * Convenience helpers for common Rift usage patterns.
 *
 * - `renderToHTML()` — static HTML string from a CellGrid (SSR / embeds)
 * - `createTerminal()` — managed terminal widget with write/clear/destroy
 * - `renderToDOM()` — quick render a CellGrid into a DOM container
 */

import { createRiftRenderer, gridToHTML } from './renderer.js';
import { injectRiftStyles } from './styles.js';
import type { CellGrid, RiftConfig, RiftRenderer } from './types.js';

/**
 * Render a CellGrid to a static HTML string.
 *
 * Useful for server-side rendering, static embeds, or clipboard export.
 */
export function renderToHTML(grid: CellGrid, config?: RiftConfig): string {
  return gridToHTML(grid, config);
}

/** A managed terminal widget with a simple write/clear/destroy API */
export interface RiftTerminal {
  /** The underlying renderer */
  renderer: RiftRenderer;
  /** Write a CellGrid to the terminal */
  write(grid: CellGrid): void;
  /** Clear the terminal display */
  clear(): void;
  /** Unmount and clean up */
  destroy(): void;
}

/**
 * Create a standalone terminal widget.
 *
 * Injects default styles, creates a renderer, and mounts it.
 */
export function createTerminal(container: HTMLElement, config?: RiftConfig): RiftTerminal {
  injectRiftStyles();
  const renderer = createRiftRenderer(config);
  renderer.mount(container);

  return {
    renderer,

    write(grid: CellGrid): void {
      renderer.render(grid);
    },

    clear(): void {
      renderer.resize(80, 24);
    },

    destroy(): void {
      renderer.unmount();
    },
  };
}

/**
 * Quick render: mount a renderer, render a CellGrid, and return the renderer.
 *
 * Injects default styles automatically.
 */
export function renderToDOM(grid: CellGrid, container: HTMLElement, options?: { cols?: number; rows?: number; config?: RiftConfig }): RiftRenderer {
  injectRiftStyles();
  const renderer = createRiftRenderer(options?.config);
  renderer.mount(container);

  if (options?.cols && options?.rows) {
    renderer.resize(options.cols, options.rows);
  }

  renderer.render(grid);
  return renderer;
}
