/**
 * DOM Renderer — turns CellGrid into DOM elements or HTML strings.
 *
 * The core of Rift: groups consecutive same-styled cells into spans,
 * supports hyperlinks, and provides diff-based updates.
 *
 * Security: All cell text is escaped via escapeHTML() before insertion.
 * CellGrid content comes from the trusted Celestial rendering pipeline,
 * not from untrusted user input.
 */

import type { CSSCellStyle } from './style-mapper.js';
import { cellStyleToCSS, cssStylesEqual, cssStyleToString } from './style-mapper.js';
import type { Cell, CellGrid, CursorPosition, ResolvedRiftConfig, RiftConfig, RiftRenderer, SelectionRange } from './types.js';
import { DEFAULT_CONFIG, resolveConfig } from './types.js';

// --- HTML rendering (pure, no DOM needed) ---

/** Escape HTML special characters to prevent injection */
function escapeHTML(str: string): string {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function sanitizeHref(href?: string): string | undefined {
  if (!href) return undefined;

  const trimmed = href.trim();
  if (!trimmed) return undefined;

  const colonIndex = trimmed.indexOf(':');
  const scheme =
    colonIndex === -1
      ? undefined
      : trimmed
          .slice(0, colonIndex)
          .replace(/[\u0000-\u001F\u007F\s]+/g, '')
          .toLowerCase();

  if (scheme === 'javascript' || scheme === 'data' || scheme === 'vbscript') {
    return undefined;
  }

  return trimmed;
}

function sanitizeFontFamily(fontFamily: string): string {
  const trimmed = fontFamily.trim();
  if (!trimmed) return DEFAULT_CONFIG.fontFamily;
  if (/[;{}*/\\\r\n\f]/.test(trimmed)) return DEFAULT_CONFIG.fontFamily;
  return trimmed;
}

function sanitizeNumber(value: number, fallback: number): number {
  const numeric = Number(value);
  return Number.isFinite(numeric) && numeric > 0 ? numeric : fallback;
}

export interface CellSpan {
  text: string;
  style: CSSCellStyle;
  href?: string;
  columns: number;
}

/**
 * Group consecutive cells in a row by identical style + href.
 * This is the key optimization: instead of one span per cell,
 * runs of same-styled cells become a single span.
 */
export function groupCells(row: Cell[]): CellSpan[] {
  if (row.length === 0) return [];

  const spans: CellSpan[] = [];
  let currentStyle = cellStyleToCSS(row[0]!.style);
  let currentHref = sanitizeHref(row[0]!.href);
  let currentText = row[0]!.char;
  let currentColumns = 1;

  for (let i = 1; i < row.length; i++) {
    const cell = row[i]!;
    const style = cellStyleToCSS(cell.style);
    const href = sanitizeHref(cell.href);

    if (cssStylesEqual(currentStyle, style) && currentHref === href) {
      currentText += cell.char;
      currentColumns += 1;
    } else {
      spans.push({ text: currentText, style: currentStyle, href: currentHref, columns: currentColumns });
      currentStyle = style;
      currentHref = href;
      currentText = cell.char;
      currentColumns = 1;
    }
  }

  spans.push({ text: currentText, style: currentStyle, href: currentHref, columns: currentColumns });
  return spans;
}

function spanStyleString(span: CellSpan): string {
  const styleStr = cssStyleToString(span.style);
  const widthStr = `width:${span.columns}ch`;
  return styleStr ? `${styleStr};${widthStr}` : widthStr;
}

/** Render a single span to an HTML string (all text is escaped) */
function spanToHTML(span: CellSpan): string {
  const styleStr = spanStyleString(span);
  const escaped = escapeHTML(span.text);
  const href = sanitizeHref(span.href);

  if (href) {
    const styleAttr = styleStr ? ` style="${escapeHTML(styleStr)}"` : '';
    return `<a href="${escapeHTML(href)}" target="_blank" rel="noopener noreferrer"${styleAttr}>${escaped}</a>`;
  }

  if (styleStr) {
    return `<span style="${escapeHTML(styleStr)}">${escaped}</span>`;
  }

  return `<span>${escaped}</span>`;
}

function renderRowContent(row: Cell[]): string {
  return groupCells(row).map(spanToHTML).join('');
}

/**
 * Render a row's children — the `<span>` runs only, without the
 * `<div class="rift-row">` wrapper. Used by clients that reuse stable row
 * elements via `row.innerHTML = innerHtml` (no node create/destroy).
 */
export function rowInnerHTML(row: Cell[]): string {
  return renderRowContent(row);
}

/** Render a single row of cells to an HTML string */
export function rowToHTML(row: Cell[]): string {
  return `<div class="rift-row" role="row">${renderRowContent(row)}</div>`;
}

/** Build the inline style string for the terminal container */
function containerStyle(config: ResolvedRiftConfig): string {
  return [
    `font-family:${sanitizeFontFamily(config.fontFamily)}`,
    `font-size:${sanitizeNumber(config.fontSize, DEFAULT_CONFIG.fontSize)}px`,
    `line-height:${sanitizeNumber(config.lineHeight, DEFAULT_CONFIG.lineHeight)}`,
    `--rift-row-height:${sanitizeNumber(config.lineHeight, DEFAULT_CONFIG.lineHeight)}em`,
  ].join(';');
}

/**
 * Render an entire CellGrid to an HTML string.
 *
 * Returns the complete `<div class="rift-terminal">...</div>` with
 * ARIA attributes for screen reader accessibility.
 */
export function gridToHTML(grid: CellGrid, config?: RiftConfig): string {
  const resolved = resolveConfig(config);
  const rows = grid.cells.map((row) => `<div class="rift-row" role="row">${renderRowContent(row)}</div>`).join('');
  const cls = resolved.className ? `rift-terminal ${escapeHTML(resolved.className)}` : 'rift-terminal';
  const style = escapeHTML(containerStyle(resolved));
  return `<div class="${cls}" style="${style}" role="log" aria-roledescription="terminal" aria-label="Terminal output" aria-live="polite">${rows}</div>`;
}

// --- Live DOM renderer ---

/**
 * Build a DOM row element from an HTML string.
 * Uses a temporary container to parse the trusted, escaped HTML.
 */
function createRowElement(html: string): Element {
  const temp = document.createElement('div');
  // SAFETY: html is built from escapeHTML()-escaped cell content
  temp.textContent = ''; // clear
  temp.insertAdjacentHTML('afterbegin', html);
  return temp.firstElementChild!;
}

// --- Cursor overlay helpers ---

function cursorOverlayCSS(config: ResolvedRiftConfig): string {
  const baseStyle = `position:absolute;pointer-events:none;z-index:1;background:${config.cursorColor}`;
  switch (config.cursorStyle) {
    case 'bar':
      return `${baseStyle};width:2px;height:1em`;
    case 'underline':
      return `${baseStyle};width:1ch;height:2px;margin-top:calc(1em - 2px)`;
    case 'block':
    default:
      return `${baseStyle};width:1ch;height:1em;opacity:0.5`;
  }
}

// --- Selection range helpers ---

function normalizeSelection(range: SelectionRange): SelectionRange {
  const { start, end } = range;
  if (start.row < end.row || (start.row === end.row && start.col <= end.col)) {
    return range;
  }
  return { start: end, end: start };
}

/**
 * Create a RiftRenderer that manages a live DOM element.
 *
 * The renderer performs diff-based updates: on subsequent `render()` calls,
 * only rows whose HTML changed are replaced in the DOM.
 */
export function createRiftRenderer(config?: RiftConfig): RiftRenderer {
  let resolved = resolveConfig(config);
  let container: HTMLElement | null = null;
  let terminalEl: HTMLElement | null = null;
  let prevRowHTML: string[] = [];
  let cursorEl: HTMLElement | null = null;
  let selectionEl: HTMLElement | null = null;
  let currentCursor: CursorPosition | null = null;
  let currentSelection: SelectionRange | null = null;
  let currentGrid: CellGrid | null = null;

  function buildTerminalElement(): HTMLElement {
    const el = document.createElement('div');
    el.className = resolved.className ? `rift-terminal ${resolved.className}` : 'rift-terminal';
    el.style.cssText = containerStyle(resolved);
    el.setAttribute('role', 'log');
    el.setAttribute('aria-roledescription', 'terminal');
    el.setAttribute('aria-label', 'Terminal output');
    el.setAttribute('aria-live', 'polite');
    el.style.position = 'relative';
    return el;
  }

  function updateCursor(): void {
    if (!terminalEl) return;

    if (!currentCursor) {
      if (cursorEl?.parentNode) cursorEl.parentNode.removeChild(cursorEl);
      cursorEl = null;
      return;
    }

    if (!cursorEl) {
      cursorEl = document.createElement('div');
      cursorEl.className = 'rift-cursor';
      cursorEl.setAttribute('aria-hidden', 'true');
    }

    cursorEl.style.cssText = cursorOverlayCSS(resolved);
    cursorEl.style.left = `${currentCursor.col}ch`;
    cursorEl.style.top = `calc(${currentCursor.row} * ${resolved.lineHeight}em)`;

    if (resolved.cursorBlink) {
      cursorEl.classList.add('rift-cursor-blink');
    } else {
      cursorEl.classList.remove('rift-cursor-blink');
    }

    if (!cursorEl.parentNode) terminalEl.appendChild(cursorEl);
  }

  function updateSelection(): void {
    if (!terminalEl) return;

    if (selectionEl?.parentNode) {
      selectionEl.parentNode.removeChild(selectionEl);
    }
    selectionEl = null;

    if (!currentSelection || !currentGrid) return;

    selectionEl = document.createElement('div');
    selectionEl.className = 'rift-selection';
    selectionEl.setAttribute('aria-hidden', 'true');
    selectionEl.style.cssText = 'position:absolute;top:0;left:0;pointer-events:none;z-index:0';

    const norm = normalizeSelection(currentSelection);
    for (let row = norm.start.row; row <= norm.end.row && row < currentGrid.height; row++) {
      const startCol = row === norm.start.row ? norm.start.col : 0;
      const endCol = row === norm.end.row ? norm.end.col : currentGrid.width;
      if (endCol <= startCol) continue;

      const highlight = document.createElement('div');
      highlight.style.cssText = [
        'position:absolute',
        `left:${startCol}ch`,
        `top:calc(${row} * ${resolved.lineHeight}em)`,
        `width:${endCol - startCol}ch`,
        `height:${resolved.lineHeight}em`,
        `background:${resolved.selectionStyle.background}`,
      ].join(';');
      selectionEl.appendChild(highlight);
    }

    terminalEl.insertBefore(selectionEl, terminalEl.firstChild);
  }

  const renderer: RiftRenderer = {
    get mounted() {
      return terminalEl !== null && container !== null && terminalEl.parentNode === container;
    },

    mount(target: HTMLElement): void {
      if (terminalEl) renderer.unmount();
      container = target;
      terminalEl = buildTerminalElement();
      container.appendChild(terminalEl);
      prevRowHTML = [];
    },

    unmount(): void {
      if (terminalEl && container && terminalEl.parentNode === container) {
        container.removeChild(terminalEl);
      }
      terminalEl = null;
      container = null;
      cursorEl = null;
      selectionEl = null;
      prevRowHTML = [];
      currentGrid = null;
    },

    render(grid: CellGrid): void {
      if (!terminalEl || !renderer.mounted) return;

      currentGrid = grid;
      const newRowHTML = grid.cells.map((row) => `<div class="rift-row" role="row">${renderRowContent(row)}</div>`);

      // Remove overlay elements before diffing (they'll be re-added after)
      if (cursorEl && cursorEl.parentNode === terminalEl) terminalEl.removeChild(cursorEl);
      if (selectionEl && selectionEl.parentNode === terminalEl) terminalEl.removeChild(selectionEl);

      if (prevRowHTML.length === 0) {
        // First render — build all rows via safe DOM construction
        for (const html of newRowHTML) {
          terminalEl.appendChild(createRowElement(html));
        }
      } else {
        // Diff update — only replace changed rows
        const children = terminalEl.children;
        const maxRows = Math.max(newRowHTML.length, prevRowHTML.length);

        for (let i = 0; i < maxRows; i++) {
          if (i >= newRowHTML.length) {
            // Row removed — always remove the element at the end
            if (children[newRowHTML.length]) {
              terminalEl.removeChild(children[newRowHTML.length]!);
            }
          } else if (i >= prevRowHTML.length) {
            // Row added
            terminalEl.appendChild(createRowElement(newRowHTML[i]!));
          } else if (newRowHTML[i] !== prevRowHTML[i]) {
            // Row changed — replace
            const newEl = createRowElement(newRowHTML[i]!);
            terminalEl.replaceChild(newEl, children[i]!);
          }
        }
      }

      prevRowHTML = newRowHTML;
      updateCursor();
      updateSelection();
    },

    resize(_cols: number, _rows: number): void {
      prevRowHTML = [];
      if (terminalEl) {
        while (terminalEl.firstChild) {
          terminalEl.removeChild(terminalEl.firstChild);
        }
      }
      cursorEl = null;
      selectionEl = null;
    },

    setConfig(newConfig: Partial<RiftConfig>): void {
      resolved = resolveConfig({ ...resolved, ...newConfig });
      if (terminalEl) {
        terminalEl.className = resolved.className ? `rift-terminal ${resolved.className}` : 'rift-terminal';
        terminalEl.style.cssText = containerStyle(resolved);
        terminalEl.style.position = 'relative';
      }
      updateCursor();
      updateSelection();
    },

    setCursor(position: CursorPosition | null): void {
      currentCursor = position;
      updateCursor();
    },

    setSelection(range: SelectionRange | null): void {
      currentSelection = range;
      updateSelection();
    },
  };

  return renderer;
}
