/**
 * Style Mapper — converts Celestial StyleAttrs into CSS properties.
 *
 * Pure function, no side effects, no DOM dependency.
 */

import { parseBg, parseFg } from './ansi-parser.js';
import type { StyleAttrs } from './types.js';

function asCssColor(value: string | undefined): string | null {
  if (!value) return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (trimmed.startsWith('\x1b[')) return null;
  if (/^rgba?\([\d\s.,%]+\)$/i.test(trimmed)) {
    return trimmed;
  }
  if (/^#(?:[\da-f]{3}|[\da-f]{4}|[\da-f]{6}|[\da-f]{8})$/i.test(trimmed)) {
    return trimmed;
  }
  return /^[a-zA-Z]+$/.test(trimmed) ? trimmed : null;
}

/** CSS properties that can be applied to a cell span */
export interface CSSCellStyle {
  color?: string;
  backgroundColor?: string;
  fontWeight?: string;
  opacity?: string;
  fontStyle?: string;
  textDecoration?: string;
}

/**
 * Convert a Celestial `StyleAttrs` object into inline CSS properties.
 *
 * - `fg` → `color` (via ANSI parser)
 * - `bg` → `backgroundColor` (via ANSI parser)
 * - `bold` → `fontWeight: '600'`
 * - `dim` → `opacity: '0.5'`
 * - `italic` → `fontStyle: 'italic'`
 * - `underline` → `textDecoration: 'underline'`
 * - `strikethrough` → `textDecoration: 'line-through'`
 * - Both underline + strikethrough → `textDecoration: 'underline line-through'`
 */
export function cellStyleToCSS(style: StyleAttrs): CSSCellStyle {
  const result: CSSCellStyle = {};

  if (style.fg) {
    const color = parseFg(style.fg) ?? asCssColor(style.fg);
    if (color) result.color = color;
  }

  if (style.bg) {
    const bgColor = parseBg(style.bg) ?? asCssColor(style.bg);
    if (bgColor) result.backgroundColor = bgColor;
  }

  if (style.bold) {
    result.fontWeight = '600';
  }

  if (style.dim) {
    result.opacity = '0.5';
  }

  if (style.italic) {
    result.fontStyle = 'italic';
  }

  const decorations: string[] = [];
  if (style.underline) decorations.push('underline');
  if (style.strikethrough) decorations.push('line-through');
  if (decorations.length > 0) {
    result.textDecoration = decorations.join(' ');
  }

  return result;
}

/**
 * Bounded LRU cache for serialized inline-CSS strings. A typical TUI repaints
 * the same handful of styles (foreground, accent, dim, error, ...) thousands
 * of times per second; allocating a fresh string per cell per frame produced
 * sustained GC pressure that surfaced as slow drift over long sessions.
 *
 * Keyed by the same six attrs that `cssStylesEqual` checks — equivalent
 * styles produce identical cache keys.
 */
const STYLE_CACHE_LIMIT = 2048;
const styleCache = new Map<string, string>();

function styleCacheKey(css: CSSCellStyle): string {
  return `${css.color ?? ''}|${css.backgroundColor ?? ''}|${css.fontWeight ?? ''}|${css.opacity ?? ''}|${css.fontStyle ?? ''}|${css.textDecoration ?? ''}`;
}

/**
 * Serialize a `CSSCellStyle` into an inline CSS string.
 *
 * Example: `'color:rgb(205,49,49);font-weight:600;'`
 */
export function cssStyleToString(css: CSSCellStyle): string {
  const key = styleCacheKey(css);
  const cached = styleCache.get(key);
  if (cached !== undefined) {
    // LRU touch: re-insert moves to the end of Map's iteration order.
    styleCache.delete(key);
    styleCache.set(key, cached);
    return cached;
  }

  const parts: string[] = [];
  if (css.color) parts.push(`color:${css.color}`);
  if (css.backgroundColor) parts.push(`background-color:${css.backgroundColor}`);
  if (css.fontWeight) parts.push(`font-weight:${css.fontWeight}`);
  if (css.opacity) parts.push(`opacity:${css.opacity}`);
  if (css.fontStyle) parts.push(`font-style:${css.fontStyle}`);
  if (css.textDecoration) parts.push(`text-decoration:${css.textDecoration}`);
  const result = parts.join(';');

  if (styleCache.size >= STYLE_CACHE_LIMIT) {
    // Evict oldest (first iteration entry).
    const oldest = styleCache.keys().next().value;
    if (oldest !== undefined) styleCache.delete(oldest);
  }
  styleCache.set(key, result);
  return result;
}

/** Clear the style cache. Test-only. */
export function _clearStyleCacheForTests(): void {
  styleCache.clear();
}

/**
 * Check whether two CSSCellStyle objects are equal.
 */
export function cssStylesEqual(a: CSSCellStyle, b: CSSCellStyle): boolean {
  return (
    a.color === b.color &&
    a.backgroundColor === b.backgroundColor &&
    a.fontWeight === b.fontWeight &&
    a.opacity === b.opacity &&
    a.fontStyle === b.fontStyle &&
    a.textDecoration === b.textDecoration
  );
}
