/**
 * RiftBridge — BroadcastChannel-based cross-tab / cross-renderer state sync
 *
 * Publishes and receives typed messages between rift renderer instances
 * running in different browser tabs or iframes sharing the same origin.
 *
 * Graceful degradation: if `globalThis.BroadcastChannel` is not available
 * (Node.js test environment, very old browsers) the bridge falls back to an
 * in-process EventTarget stub so all synchronous subscribe/publish pairs still
 * work in tests.
 *
 * Usage:
 *   const bridge = createRiftBridge({ channel: 'my-app' });
 *   bridge.publish('focus', { focusId: 'panel-1', ts: Date.now() });
 *   bridge.subscribe((msg) => console.log(msg.kind, msg.payload));
 *   bridge.destroy();
 */

// --- Message shape ---

/** Well-known message kinds. Callers may extend via the string union. */
export type RiftBridgeKind = 'focus' | 'clipboard' | 'selection' | (string & {});

/** Payload shapes for built-in message kinds */
export interface RiftBridgeFocusPayload {
  focusId: string;
  ts: number;
}

export interface RiftBridgeClipboardPayload {
  text: string;
}

export interface RiftBridgeSelectionPayload {
  range: {
    start: { row: number; col: number };
    end: { row: number; col: number };
  } | null;
}

/** Generic bridge message envelope */
export interface RiftBridgeMessage<K extends RiftBridgeKind = RiftBridgeKind, P = unknown> {
  kind: K;
  payload: P;
  ts: number;
}

/** Overloaded publish signatures for well-known kinds */
export interface RiftBridgePublishOverloads {
  (kind: 'focus', payload: RiftBridgeFocusPayload): void;
  (kind: 'clipboard', payload: RiftBridgeClipboardPayload): void;
  (kind: 'selection', payload: RiftBridgeSelectionPayload): void;
  (kind: string, payload: unknown): void;
}

/** Subscriber callback type */
export type RiftBridgeSubscriber = (message: RiftBridgeMessage) => void;

/** The public RiftBridge handle */
export interface RiftBridge {
  /** Publish a message to all other bridge instances on the same channel */
  publish: RiftBridgePublishOverloads;
  /** Subscribe to messages from other bridge instances */
  subscribe(callback: RiftBridgeSubscriber): () => void;
  /** Tear down the bridge (closes the BroadcastChannel and unsubscribes all) */
  destroy(): void;
  /** Channel name this bridge is connected to */
  readonly channelName: string;
}

/** Configuration for `createRiftBridge` */
export interface RiftBridgeConfig {
  /**
   * BroadcastChannel name. Use a stable, app-scoped identifier like
   * `'celestial-<app-id>'` so multiple apps on the same origin don't collide.
   */
  channel: string;
}

// --- In-process stub for environments without BroadcastChannel ---

/**
 * Minimal in-process BroadcastChannel-compatible stub.
 *
 * Used in Node / vitest environments where globalThis.BroadcastChannel is
 * absent. Multiple stubs that share the same `name` exchange messages via a
 * shared EventTarget bus so bidirectional sync tests work without a real
 * browser context.
 */
const _stubBuses = new Map<string, EventTarget>();

function getStubBus(name: string): EventTarget {
  let bus = _stubBuses.get(name);
  if (!bus) {
    bus = new EventTarget();
    _stubBuses.set(name, bus);
  }
  return bus;
}

/** @internal — clear stub buses between tests */
export function _clearRiftBridgeStubs(): void {
  _stubBuses.clear();
}

interface BroadcastLike {
  postMessage(data: unknown): void;
  addEventListener(type: 'message', listener: (event: { data: unknown }) => void): void;
  removeEventListener(type: 'message', listener: (event: { data: unknown }) => void): void;
  close(): void;
  readonly name: string;
}

function createStubChannel(name: string): BroadcastLike {
  const bus = getStubBus(name);
  const listeners = new Set<(event: { data: unknown }) => void>();

  // Unique symbol so each stub instance can distinguish its own messages.
  const instanceId = Math.random().toString(36).slice(2);

  function onBusEvent(ev: Event): void {
    const ce = ev as CustomEvent<{ senderId: string; data: unknown }>;
    // Skip messages sent by this same stub instance (mirrors BroadcastChannel
    // behaviour: you do NOT receive your own posts).
    if (ce.detail.senderId === instanceId) return;
    const synth = { data: ce.detail.data };
    for (const listener of listeners) {
      listener(synth);
    }
  }

  bus.addEventListener('rift-bridge-msg', onBusEvent);

  return {
    name,
    postMessage(data: unknown): void {
      bus.dispatchEvent(new CustomEvent('rift-bridge-msg', { detail: { senderId: instanceId, data } }));
    },
    addEventListener(_type: 'message', listener: (event: { data: unknown }) => void): void {
      listeners.add(listener);
    },
    removeEventListener(_type: 'message', listener: (event: { data: unknown }) => void): void {
      listeners.delete(listener);
    },
    close(): void {
      bus.removeEventListener('rift-bridge-msg', onBusEvent);
      listeners.clear();
    },
  };
}

function openChannel(name: string): BroadcastLike {
  // Use the native BroadcastChannel only in browser environments (where `window`
  // is defined). Node 18+ exposes `BroadcastChannel` on globalThis but its
  // message delivery is asynchronous (via the worker_threads message passing
  // system), which breaks synchronous tests and makes it unusable as a simple
  // in-process pub/sub primitive. Fall back to the stub in Node/vitest.
  if (typeof globalThis.BroadcastChannel !== 'undefined' && typeof globalThis.window !== 'undefined') {
    return new globalThis.BroadcastChannel(name) as unknown as BroadcastLike;
  }
  return createStubChannel(name);
}

// --- Public factory ---

/**
 * Create a RiftBridge connected to the named BroadcastChannel.
 *
 * Multiple bridge instances sharing the same `channel` name exchange messages
 * bidirectionally. Each instance does NOT receive its own published messages
 * (mirrors native BroadcastChannel semantics).
 *
 * Call `bridge.destroy()` when the renderer unmounts to close the channel.
 */
export function createRiftBridge(config: RiftBridgeConfig): RiftBridge {
  const { channel } = config;
  const bc = openChannel(channel);
  const subscribers = new Set<RiftBridgeSubscriber>();

  function handleIncoming(event: { data: unknown }): void {
    const msg = event.data as RiftBridgeMessage;
    if (!msg || typeof msg.kind !== 'string') return;
    for (const sub of subscribers) {
      try {
        sub(msg);
      } catch {
        // best-effort — subscriber errors must not break the loop
      }
    }
  }

  bc.addEventListener('message', handleIncoming);

  const bridge: RiftBridge = {
    get channelName() {
      return channel;
    },

    publish(kind: string, payload: unknown): void {
      const msg: RiftBridgeMessage = { kind, payload, ts: Date.now() };
      try {
        bc.postMessage(msg);
      } catch {
        // best-effort — swallow DataCloneError for un-structured-cloneable payloads
      }
    },

    subscribe(callback: RiftBridgeSubscriber): () => void {
      subscribers.add(callback);
      return () => {
        subscribers.delete(callback);
      };
    },

    destroy(): void {
      bc.removeEventListener('message', handleIncoming);
      bc.close();
      subscribers.clear();
    },
  } as unknown as RiftBridge;

  // Cast is needed because publish has an overloaded signature but the
  // implementation is a single function with `(kind: string, payload: unknown)`.
  return bridge;
}
