/**
 * Rift — Browser-compatible CellGrid renderer for Celestial TUI
 *
 * Replaces ANSI output with DOM rendering, making Celestial work in browsers.
 */

// --- Re-declare Celestial cell types so Rift stays zero-dependency ---

/** ANSI style attributes attached to a terminal cell */
export interface StyleAttrs {
  fg?: string;
  bg?: string;
  bold?: boolean;
  dim?: boolean;
  italic?: boolean;
  underline?: boolean;
  strikethrough?: boolean;
}

/** A single terminal cell */
export interface Cell {
  char: string;
  style: StyleAttrs;
  /** OSC 8 hyperlink target */
  href?: string;
}

/** A 2-D grid of terminal cells */
export interface CellGrid {
  cells: Cell[][]; // [row][col]
  width: number;
  height: number;
}

// --- Cursor configuration ---

/** Cursor visual style */
export type CursorStyle = 'block' | 'bar' | 'underline';

/** Cursor position in the terminal grid */
export interface CursorPosition {
  row: number;
  col: number;
}

// --- Selection ---

/** A text selection range in the terminal grid */
export interface SelectionRange {
  start: CursorPosition;
  end: CursorPosition;
}

/** Styling for the selection highlight */
export interface SelectionStyle {
  /** Background color for selected cells. Default: `'rgba(174,186,211,0.3)'` */
  background?: string;
}

// --- Rift configuration ---

/** Configuration options for the Rift renderer */
export interface RiftConfig {
  /** Monospace font family or array of fallback families. Default: `'Geist Mono, monospace'` */
  fontFamily?: string | string[];
  /** Font size in pixels. Default: `13` */
  fontSize?: number;
  /** Line height multiplier. Default: `1.4` */
  lineHeight?: number;
  /** Whether the cursor blinks. Default: `true` */
  cursorBlink?: boolean;
  /** Cursor visual style. Default: `'block'` */
  cursorStyle?: CursorStyle;
  /** Cursor color. Default: `'#c8d6e5'` */
  cursorColor?: string;
  /** Custom CSS class applied to the container element */
  className?: string;
  /** Selection highlight styling */
  selectionStyle?: SelectionStyle;
}

/** Resolved configuration with all defaults applied */
export interface ResolvedRiftConfig {
  fontFamily: string;
  fontSize: number;
  lineHeight: number;
  cursorBlink: boolean;
  cursorStyle: CursorStyle;
  cursorColor: string;
  className: string;
  selectionStyle: Required<SelectionStyle>;
}

/** The public renderer interface */
export interface RiftRenderer {
  /** Attach to a DOM container */
  mount(container: HTMLElement): void;
  /** Detach from the DOM */
  unmount(): void;
  /** Render a CellGrid into the mounted container */
  render(grid: CellGrid): void;
  /** Update logical grid dimensions */
  resize(cols: number, rows: number): void;
  /** Merge partial config updates */
  setConfig(config: Partial<RiftConfig>): void;
  /** Set cursor position (null to hide cursor) */
  setCursor(position: CursorPosition | null): void;
  /** Set text selection range (null to clear selection) */
  setSelection(range: SelectionRange | null): void;
  /** Whether the renderer is currently mounted */
  readonly mounted: boolean;
}

// --- Defaults ---

export const DEFAULT_SELECTION_STYLE: Required<SelectionStyle> = {
  background: 'rgba(174,186,211,0.3)',
};

export const DEFAULT_CONFIG: ResolvedRiftConfig = {
  fontFamily: 'Geist Mono, monospace',
  fontSize: 13,
  lineHeight: 1.4,
  cursorBlink: true,
  cursorStyle: 'block',
  cursorColor: '#c8d6e5',
  className: '',
  selectionStyle: { ...DEFAULT_SELECTION_STYLE },
};

/** Normalize a fontFamily value (string or array) into a CSS-ready string */
export function normalizeFontFamily(value?: string | string[]): string {
  if (!value) return DEFAULT_CONFIG.fontFamily;
  if (typeof value === 'string') return value;
  return (
    value
      .map((f) => {
        const trimmed = f.trim();
        // Quote font names containing spaces (but not CSS keywords like monospace, serif, etc.)
        if (/\s/.test(trimmed) && !/^(?:serif|sans-serif|monospace|cursive|fantasy|system-ui|ui-monospace)$/i.test(trimmed)) {
          const escaped = trimmed.replace(/\\/g, '\\\\').replace(/'/g, "\\'");
          return `'${escaped}'`;
        }
        return trimmed;
      })
      .filter(Boolean)
      .join(', ') || DEFAULT_CONFIG.fontFamily
  );
}

export function resolveConfig(config?: RiftConfig): ResolvedRiftConfig {
  const fontFamily = normalizeFontFamily(config?.fontFamily);
  return {
    ...DEFAULT_CONFIG,
    ...config,
    fontFamily,
    selectionStyle: { ...DEFAULT_SELECTION_STYLE, ...config?.selectionStyle },
  };
}
