/**
 * ANSI SGR escape-sequence parser.
 *
 * Converts ANSI color codes into CSS `rgb()` strings.
 * Handles standard (8-color), bright (16-color), 256-color, and true-color.
 */

// --- 16 standard ANSI colors (dark 0-7, bright 8-15) ---

const ANSI_16: readonly string[] = [
  'rgb(0,0,0)', // 0 black
  'rgb(205,49,49)', // 1 red
  'rgb(13,188,121)', // 2 green
  'rgb(229,229,16)', // 3 yellow
  'rgb(36,114,200)', // 4 blue
  'rgb(188,63,188)', // 5 magenta
  'rgb(17,168,205)', // 6 cyan
  'rgb(204,204,204)', // 7 white
  'rgb(102,102,102)', // 8 bright black
  'rgb(241,76,76)', // 9 bright red
  'rgb(35,209,139)', // 10 bright green
  'rgb(245,245,67)', // 11 bright yellow
  'rgb(59,142,234)', // 12 bright blue
  'rgb(214,112,214)', // 13 bright magenta
  'rgb(41,184,219)', // 14 bright cyan
  'rgb(242,242,242)', // 15 bright white
];

/**
 * Convert a 256-color index to an `rgb()` CSS string.
 *
 * 0-15   → standard 16 colors
 * 16-231 → 6x6x6 color cube
 * 232-255 → grayscale ramp
 */
function color256ToCSS(index: number): string | null {
  if (index < 0 || index > 255) return null;

  if (index < 16) return ANSI_16[index]!;

  if (index < 232) {
    // 6x6x6 color cube: index = 16 + 36*r + 6*g + b  (each 0-5)
    const ci = index - 16;
    const b = ci % 6;
    const g = Math.floor(ci / 6) % 6;
    const r = Math.floor(ci / 36);
    const toVal = (v: number) => (v === 0 ? 0 : 55 + v * 40);
    return `rgb(${toVal(r)},${toVal(g)},${toVal(b)})`;
  }

  // 232-255: grayscale ramp  (8 + i*10 for i=0..23)
  const gray = 8 + (index - 232) * 10;
  return `rgb(${gray},${gray},${gray})`;
}

/**
 * Parse a single ANSI SGR escape sequence and return a CSS color string.
 *
 * Accepts the full escape sequence (e.g. `'\x1b[31m'`).
 * Returns `null` for reset, unrecognised, or non-color sequences.
 */
export function parseAnsiColor(ansi: string): string | null {
  if (!ansi) return null;

  // Strip ESC[ prefix and trailing 'm'
  const match = ansi.match(/\x1b\[([\d;]*)m/);
  if (!match) return null;

  const params = match[1]!.split(';').map(Number);
  if (params.length === 0) return null;

  return parseParams(params);
}

function parseParams(params: number[]): string | null {
  const code = params[0]!;

  // Standard foreground 30-37
  if (code >= 30 && code <= 37) return ANSI_16[code - 30]!;

  // Bright foreground 90-97
  if (code >= 90 && code <= 97) return ANSI_16[code - 90 + 8]!;

  // Standard background 40-47
  if (code >= 40 && code <= 47) return ANSI_16[code - 40]!;

  // Bright background 100-107
  if (code >= 100 && code <= 107) return ANSI_16[code - 100 + 8]!;

  // Extended color: 38;5;N (fg 256) or 38;2;R;G;B (fg truecolor)
  if (code === 38 || code === 48) {
    if (params.length >= 3 && params[1] === 5) {
      return color256ToCSS(params[2]!);
    }
    if (params.length >= 5 && params[1] === 2) {
      const r = clamp(params[2]!, 0, 255);
      const g = clamp(params[3]!, 0, 255);
      const b = clamp(params[4]!, 0, 255);
      return `rgb(${r},${g},${b})`;
    }
  }

  return null;
}

function clamp(v: number, min: number, max: number): number {
  return v < min ? min : v > max ? max : v;
}

/**
 * Extract the foreground CSS color from an ANSI escape.
 * Returns `null` for background-only or non-color sequences.
 */
export function parseFg(ansi: string): string | null {
  if (!ansi) return null;
  const match = ansi.match(/\x1b\[([\d;]*)m/);
  if (!match) return null;

  const params = match[1]!.split(';').map(Number);
  if (params.length === 0) return null;

  const code = params[0]!;

  // Foreground ranges
  if (code >= 30 && code <= 37) return ANSI_16[code - 30]!;
  if (code >= 90 && code <= 97) return ANSI_16[code - 90 + 8]!;
  if (code === 38) {
    if (params.length >= 3 && params[1] === 5) return color256ToCSS(params[2]!);
    if (params.length >= 5 && params[1] === 2) {
      return `rgb(${clamp(params[2]!, 0, 255)},${clamp(params[3]!, 0, 255)},${clamp(params[4]!, 0, 255)})`;
    }
  }

  return null;
}

/**
 * Extract the background CSS color from an ANSI escape.
 * Returns `null` for foreground-only or non-color sequences.
 */
export function parseBg(ansi: string): string | null {
  if (!ansi) return null;
  const match = ansi.match(/\x1b\[([\d;]*)m/);
  if (!match) return null;

  const params = match[1]!.split(';').map(Number);
  if (params.length === 0) return null;

  const code = params[0]!;

  // Background ranges
  if (code >= 40 && code <= 47) return ANSI_16[code - 40]!;
  if (code >= 100 && code <= 107) return ANSI_16[code - 100 + 8]!;
  if (code === 48) {
    if (params.length >= 3 && params[1] === 5) return color256ToCSS(params[2]!);
    if (params.length >= 5 && params[1] === 2) {
      return `rgb(${clamp(params[2]!, 0, 255)},${clamp(params[3]!, 0, 255)},${clamp(params[4]!, 0, 255)})`;
    }
  }

  return null;
}
