/**
 * Rift Surface — universal close-affordance pipeline
 *
 * Mirrors the `applySurfaceOpen` pattern from packages/portal/src/mirror.ts.
 * Every surface rendered by rift (modal, overlay, sidebar, toast, popover,
 * dialog, drawer) unconditionally receives:
 *
 *  - A visible ✕ close button in the top-right corner
 *  - An Escape-key handler bound at surface mount
 *  - For modals: a backdrop-click dismiss handler
 *  - A panic shortcut (Ctrl/Cmd+Shift+Backspace) that clears ALL open surfaces
 *
 * Design contract (from CLAUDE.md, P0):
 *  - DOM removal is ALWAYS optimistic on user action — never gated on a server ack.
 *  - Surfaces must be opaque even outside theme-variable scope: hardcoded
 *    fallback background `#1a1d23` is applied unconditionally.
 *  - There is NO non-dismissible surface. If a caller needs a forced answer,
 *    "dismissed" is a valid response that the caller must handle.
 */

/** Recognised surface kind discriminants */
export type RiftSurfaceKind = 'modal' | 'overlay' | 'sidebar' | 'toast' | 'popover' | 'dialog' | 'drawer';

/** Metadata provided when opening a rift surface */
export interface RiftSurfaceMeta {
  /** Stable identifier for this surface instance */
  requestId: string;
  /** Visual category of the surface */
  surface: RiftSurfaceKind;
  /** Optional tool or component name for CSS data-tool scoping */
  toolName?: string;
}

/** Result emitted when a surface is dismissed by the user */
export interface RiftSurfaceDismissEvent {
  requestId: string;
  action: 'dismissed';
}

/** Callback invoked when the user dismisses a surface */
export type RiftSurfaceDismissCallback = (event: RiftSurfaceDismissEvent) => void;

// --- Fallback background (opaque, never relies on CSS-variable cascade) ---
const SURFACE_FALLBACK_BG = '#1a1d23';

// --- Registry of all open surfaces for panic-clear ---
/** @internal */
const _openSurfaces = new Map<string, { instance: HTMLElement; onDismiss: RiftSurfaceDismissCallback }>();

/** @internal — exported only for testing */
export function _getRiftOpenSurfaces(): ReadonlyMap<string, { instance: HTMLElement; onDismiss: RiftSurfaceDismissCallback }> {
  return _openSurfaces;
}

// --- Panic shortcut listener (installed once, lazily) ---

let _panicListenerInstalled = false;

function installPanicListener(): void {
  if (_panicListenerInstalled) return;
  if (typeof window === 'undefined') return;
  _panicListenerInstalled = true;

  window.addEventListener('keydown', (event: KeyboardEvent) => {
    // Ctrl/Cmd + Shift + Backspace nukes ALL open surfaces unconditionally.
    const isBackspace = event.key === 'Backspace';
    const hasMod = event.ctrlKey || event.metaKey;
    if (isBackspace && hasMod && event.shiftKey) {
      event.preventDefault();
      const ids = Array.from(_openSurfaces.keys());
      for (const id of ids) {
        dismissLocally(id);
      }
    }
  });
}

// --- Core dismiss logic ---

function dismissLocally(requestId: string): void {
  const entry = _openSurfaces.get(requestId);
  if (!entry) return;

  // DOM removal is optimistic — happens immediately, before notifying caller.
  if (entry.instance.parentNode) {
    entry.instance.parentNode.removeChild(entry.instance);
  }
  _openSurfaces.delete(requestId);

  // Notify caller as best-effort. If caller throws, the surface is still gone.
  try {
    entry.onDismiss({ requestId, action: 'dismissed' });
  } catch {
    // best-effort — swallow caller errors
  }
}

// --- Per-surface Escape handler ---

function makeEscapeHandler(requestId: string): (event: KeyboardEvent) => void {
  return (event: KeyboardEvent) => {
    if (event.key === 'Escape' && !event.defaultPrevented) {
      event.preventDefault();
      dismissLocally(requestId);
    }
  };
}

// --- ✕ close button ---

function appendCloseButton(card: HTMLElement, requestId: string): void {
  const btn = document.createElement('button');
  btn.type = 'button';
  btn.className = 'rift-surface-close';
  btn.setAttribute('aria-label', 'Close');
  btn.setAttribute('title', 'Close (Esc)');
  btn.textContent = 'x';
  btn.style.cssText = [
    'position:absolute',
    'top:8px',
    'right:8px',
    'z-index:10',
    'width:24px',
    'height:24px',
    'display:flex',
    'align-items:center',
    'justify-content:center',
    'background:transparent',
    'border:1px solid rgba(255,255,255,0.2)',
    'border-radius:4px',
    'color:rgba(255,255,255,0.7)',
    'font-size:14px',
    'line-height:1',
    'cursor:pointer',
    'padding:0',
  ].join(';');

  btn.addEventListener('click', (event: Event) => {
    event.preventDefault();
    event.stopPropagation();
    dismissLocally(requestId);
  });

  card.appendChild(btn);
}

// --- Public API ---

/**
 * Apply the universal rift surface-open pattern to a container element.
 *
 * Creates a surface instance div, appends it to `surfaceRoot`, attaches:
 *  - Hardcoded fallback background so the surface is always opaque
 *  - A ✕ close button (top-right of the card)
 *  - An Escape-key handler
 *  - For modals: a backdrop-click dismiss
 *  - A panic shortcut (Ctrl/Cmd+Shift+Backspace) — installed globally once
 *
 * DOM removal is optimistic: `onDismiss` is called after the element is removed.
 *
 * @returns The surface instance element (the backdrop/wrapper div)
 */
export function applyRiftSurfaceOpen(surfaceRoot: HTMLElement, meta: RiftSurfaceMeta, onDismiss: RiftSurfaceDismissCallback): HTMLElement {
  // Remove any previous surface with the same requestId before re-mounting.
  if (_openSurfaces.has(meta.requestId)) {
    dismissLocally(meta.requestId);
  }

  // --- Outer instance (backdrop / positioning wrapper) ---
  const instance = document.createElement('div');
  instance.className = `rift-surface-instance ${meta.surface}`;
  instance.setAttribute('data-request-id', meta.requestId);
  instance.setAttribute('role', meta.surface === 'modal' || meta.surface === 'dialog' ? 'dialog' : 'region');
  instance.setAttribute('aria-modal', meta.surface === 'modal' || meta.surface === 'dialog' ? 'true' : 'false');
  if (meta.toolName) instance.setAttribute('data-tool', meta.toolName);

  // --- Inner card (content container) ---
  const card = document.createElement('div');
  card.className = 'rift-surface-card';
  if (meta.toolName) card.setAttribute('data-tool', meta.toolName);
  // Hardcoded fallback background — opaque regardless of theme-variable scope.
  card.style.cssText = `position:relative;background:${SURFACE_FALLBACK_BG}`;

  instance.appendChild(card);
  surfaceRoot.appendChild(instance);

  // Register before attaching handlers so dismissLocally can find it.
  _openSurfaces.set(meta.requestId, { instance, onDismiss });

  // --- ✕ close button on the card ---
  appendCloseButton(card, meta.requestId);

  // --- Escape key handler (bound at document, scoped to this surface) ---
  const escapeHandler = makeEscapeHandler(meta.requestId);
  document.addEventListener('keydown', escapeHandler);

  // Clean up the Escape listener when the surface is dismissed. Wrap onDismiss
  // so that the keyboard listener is always removed regardless of who initiates
  // the close (✕, backdrop, Escape, panic, or external `removeRiftSurface`).
  const originalEntry = _openSurfaces.get(meta.requestId)!;
  _openSurfaces.set(meta.requestId, {
    instance,
    onDismiss: (event) => {
      document.removeEventListener('keydown', escapeHandler);
      originalEntry.onDismiss(event);
    },
  });

  // --- Backdrop-click dismiss (modals only) ---
  if (meta.surface === 'modal' || meta.surface === 'dialog') {
    instance.addEventListener('click', (event: Event) => {
      // Only dismiss when clicking the backdrop itself, not the card.
      if (event.target === instance) {
        dismissLocally(meta.requestId);
      }
    });
  }

  // --- Absorb pointer events on the card so they don't leak to underlying UI ---
  function stopProp(event: Event): void {
    event.stopPropagation();
  }
  card.addEventListener('mousedown', stopProp);
  card.addEventListener('mouseup', stopProp);
  card.addEventListener('click', stopProp);
  card.addEventListener('wheel', stopProp);
  instance.addEventListener('mousedown', stopProp);
  instance.addEventListener('mouseup', stopProp);
  instance.addEventListener('wheel', stopProp);

  // --- Panic shortcut (Ctrl/Cmd+Shift+Backspace) — installed globally once ---
  installPanicListener();

  return instance;
}

/**
 * Programmatically remove a rift surface by requestId.
 *
 * Equivalent to the user pressing ✕ — DOM is removed optimistically,
 * `onDismiss` is called as best-effort afterward.
 */
export function removeRiftSurface(requestId: string): boolean {
  if (!_openSurfaces.has(requestId)) return false;
  dismissLocally(requestId);
  return true;
}

/**
 * Remove ALL open rift surfaces (equivalent to the panic shortcut).
 * Useful in tests and in shutdown paths.
 */
export function clearAllRiftSurfaces(): void {
  const ids = Array.from(_openSurfaces.keys());
  for (const id of ids) {
    dismissLocally(id);
  }
}

/** Returns the number of currently-open rift surfaces */
export function riftSurfaceCount(): number {
  return _openSurfaces.size;
}
