/**
 * Rift Graphics — Sixel/Kitty escape-sequence detector and <canvas> adapter
 *
 * Detects sixel (`\x1bP...q`) and kitty-graphics (`\x1b_G...\x1b\\`) escape
 * sequences in cell payloads and renders decoded pixel data onto a `<canvas>`
 * element layered over the affected cell region.
 *
 * This lets `@celestial/prism` image rendering work inside rift without a
 * separate fallback path: prism writes graphics escapes into cell content,
 * rift detects them here and lifts them out of the text layer into canvas.
 *
 * Implementation notes:
 *  - Sixel: `\x1bP` ... `q` ... `\x1b\\` (DCS P...q ST)
 *  - Kitty: `\x1b_G` key=value pairs ... `\x1b\\` (APC G ST)
 *  - Decoding is behind a pluggable `decodeSixel` / `decodeKitty` hook so
 *    callers can supply a full decoder; the built-in stubs return `null`
 *    (region tracking still works, canvas is mounted but left blank).
 *    TODO: implement real sixel DCS and kitty base64→RGBA decoders.
 */

// --- Escape sequence detection ---

/** Sixel DCS: ESC P ... q (payload) ... ESC \ */
const SIXEL_RE = /\x1bP[^q]*q([\s\S]*?)\x1b\\/g;

/** Kitty APC: ESC _ G key=val,... ; data ESC \ */
const KITTY_RE = /\x1b_G([\s\S]*?)\x1b\\/g;

export type GraphicsProtocol = 'sixel' | 'kitty';

/** A detected graphics escape sequence within a cell string */
export interface DetectedGraphicsSequence {
  protocol: GraphicsProtocol;
  /** Raw payload content (sixel body / kitty parameters+data) */
  payload: string;
  /** Byte offset of the escape within the source string */
  offset: number;
}

/**
 * Scan `text` for sixel and kitty graphics escape sequences.
 * Returns all detected sequences in source order.
 */
export function detectGraphicsSequences(text: string): DetectedGraphicsSequence[] {
  const results: DetectedGraphicsSequence[] = [];

  let m: RegExpExecArray | null;

  SIXEL_RE.lastIndex = 0;
  while ((m = SIXEL_RE.exec(text)) !== null) {
    results.push({ protocol: 'sixel', payload: m[1] ?? '', offset: m.index });
  }

  KITTY_RE.lastIndex = 0;
  while ((m = KITTY_RE.exec(text)) !== null) {
    results.push({ protocol: 'kitty', payload: m[1] ?? '', offset: m.index });
  }

  results.sort((a, b) => a.offset - b.offset);
  return results;
}

// --- Decoder hooks (pluggable; stubs return null) ---

/**
 * Decode a sixel payload string into an ImageData object.
 *
 * TODO: implement DCS sixel raster format decoder.
 *   Sixel encodes pixel rows using a palette + run-length encoded characters
 *   in the range '?' (63) to '~' (126), each encoding a 6-pixel column.
 *   Reference: https://www.vt100.net/docs/vt3xx-gp/chapter14.html
 *
 * @returns Decoded ImageData or null if decoding fails / not implemented.
 */
export type SixelDecoder = (payload: string) => ImageData | null;

/**
 * Decode a kitty graphics payload string into an ImageData object.
 *
 * TODO: implement kitty graphics protocol decoder.
 *   Kitty encodes raw RGBA pixel data as base64. The payload starts with
 *   comma-separated key=value pairs (f=32 for RGBA, s=width, v=height),
 *   followed by a semicolon and the base64 image data.
 *   Reference: https://sw.kovidgoyal.net/kitty/graphics-protocol/
 *
 * @returns Decoded ImageData or null if decoding fails / not implemented.
 */
export type KittyDecoder = (payload: string) => ImageData | null;

/** Default no-op sixel decoder stub */
export function decodeSixel(_payload: string): ImageData | null {
  // TODO: implement sixel DCS raster format decoder
  return null;
}

/** Default no-op kitty decoder stub */
export function decodeKitty(_payload: string): ImageData | null {
  // TODO: implement kitty graphics protocol base64→RGBA decoder
  return null;
}

// --- Cell region tracking ---

/** A rectangular cell region (in terminal grid coordinates) */
export interface CellRegion {
  row: number;
  col: number;
  widthCells: number;
  heightCells: number;
}

/**
 * A mounted canvas overlay representing one decoded graphics sequence.
 * The canvas is sized to cover the affected cell region.
 */
export interface GraphicsOverlay {
  /** The <canvas> element mounted into the DOM */
  canvas: HTMLCanvasElement;
  /** Cell region this overlay covers */
  region: CellRegion;
  /** Protocol that produced this overlay */
  protocol: GraphicsProtocol;
  /** Whether pixel data was successfully decoded and drawn */
  decoded: boolean;
}

// --- Canvas adapter ---

/** Configuration for the graphics canvas adapter */
export interface RiftGraphicsAdapterConfig {
  /** Cell width in pixels (typically `fontSize` × average char advance ≈ 1ch) */
  cellWidthPx: number;
  /** Cell height in pixels (typically `fontSize × lineHeight`) */
  cellHeightPx: number;
  /** Custom sixel decoder (defaults to the no-op stub) */
  decodeSixel?: SixelDecoder;
  /** Custom kitty decoder (defaults to the no-op stub) */
  decodeKitty?: KittyDecoder;
}

/** The adapter handle returned by `createRiftGraphicsAdapter` */
export interface RiftGraphicsAdapter {
  /**
   * Scan `text` for graphics sequences and mount canvas overlays into
   * `container` at the given cell origin.
   *
   * `container` should be the terminal element (`position: relative`).
   * Each overlay is absolutely positioned over the originating cell region.
   *
   * @returns Array of mounted overlays (may be empty if no sequences found)
   */
  mountGraphics(container: HTMLElement, text: string, origin: { row: number; col: number }): GraphicsOverlay[];

  /**
   * Remove all canvas overlays previously mounted by this adapter instance.
   * Call this on every render cycle before re-scanning, or on unmount.
   */
  clearOverlays(): void;

  /** All currently mounted overlays */
  readonly overlays: readonly GraphicsOverlay[];
}

/**
 * Estimate the pixel dimensions of an image encoded in a graphics sequence.
 *
 * This is a best-effort heuristic: for sixel we try to parse the raster
 * attributes header; for kitty we parse the `s=` (width) and `v=` (height)
 * key-value pairs. Falls back to a single-cell region if parsing fails.
 */
function estimateRegion(origin: { row: number; col: number }, seq: DetectedGraphicsSequence, cellWidthPx: number, cellHeightPx: number): CellRegion {
  let widthPx = cellWidthPx;
  let heightPx = cellHeightPx;

  if (seq.protocol === 'kitty') {
    // Kitty: s=<cols>,v=<rows> in the key-value section before the semicolon
    const kvSection = seq.payload.split(';')[0] ?? '';
    const sw = /\bs=(\d+)/.exec(kvSection);
    const sv = /\bv=(\d+)/.exec(kvSection);
    if (sw) widthPx = parseInt(sw[1]!, 10);
    if (sv) heightPx = parseInt(sv[1]!, 10);
  } else if (seq.protocol === 'sixel') {
    // Sixel: raster attributes are `"<pan>;<pad>;<ph>;<pv>` before the body
    const ra = /^"(\d+);(\d+);(\d+);(\d+)/.exec(seq.payload.trimStart());
    if (ra) {
      widthPx = parseInt(ra[3]!, 10);
      heightPx = parseInt(ra[4]!, 10);
    }
  }

  return {
    row: origin.row,
    col: origin.col,
    widthCells: Math.max(1, Math.ceil(widthPx / cellWidthPx)),
    heightCells: Math.max(1, Math.ceil(heightPx / cellHeightPx)),
  };
}

/**
 * Create a RiftGraphicsAdapter that detects and renders sixel/kitty images.
 *
 * The adapter maintains a list of mounted canvas overlays. Call
 * `clearOverlays()` before each render pass, then `mountGraphics()` for each
 * cell row that may contain graphics sequences.
 */
export function createRiftGraphicsAdapter(config: RiftGraphicsAdapterConfig): RiftGraphicsAdapter {
  const { cellWidthPx, cellHeightPx, decodeSixel: sixelDecoder = decodeSixel, decodeKitty: kittyDecoder = decodeKitty } = config;

  const _overlays: GraphicsOverlay[] = [];

  function clearOverlays(): void {
    for (const overlay of _overlays) {
      if (overlay.canvas.parentNode) {
        overlay.canvas.parentNode.removeChild(overlay.canvas);
      }
    }
    _overlays.length = 0;
  }

  function mountGraphics(container: HTMLElement, text: string, origin: { row: number; col: number }): GraphicsOverlay[] {
    const sequences = detectGraphicsSequences(text);
    if (sequences.length === 0) return [];

    const mounted: GraphicsOverlay[] = [];

    for (const seq of sequences) {
      const region = estimateRegion(origin, seq, cellWidthPx, cellHeightPx);

      // Create and size the canvas to cover the cell region.
      const canvas = document.createElement('canvas');
      canvas.width = region.widthCells * cellWidthPx;
      canvas.height = region.heightCells * cellHeightPx;
      canvas.style.cssText = [
        'position:absolute',
        `left:${region.col}ch`,
        `top:calc(${region.row} * ${cellHeightPx}px)`,
        `width:${region.widthCells}ch`,
        `height:${region.heightCells * cellHeightPx}px`,
        'z-index:2',
        'pointer-events:none',
        'image-rendering:pixelated',
      ].join(';');
      canvas.setAttribute('aria-hidden', 'true');

      container.appendChild(canvas);

      // Attempt to decode and render pixel data.
      let decoded = false;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const imageData = seq.protocol === 'sixel' ? sixelDecoder(seq.payload) : kittyDecoder(seq.payload);

        if (imageData) {
          ctx.putImageData(imageData, 0, 0);
          decoded = true;
        }
        // If decoding returned null (stub or failure), canvas is transparent.
        // The region is still tracked for layout purposes.
      }

      const overlay: GraphicsOverlay = { canvas, region, protocol: seq.protocol, decoded };
      _overlays.push(overlay);
      mounted.push(overlay);
    }

    return mounted;
  }

  return {
    mountGraphics,
    clearOverlays,
    get overlays(): readonly GraphicsOverlay[] {
      return _overlays;
    },
  };
}
